#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use HTML::Entities;

my $cgi = CGI->new;
my $comment_raw = $cgi->param('comment') // '';

# Sanitize the comment to prevent XSS while allowing basic formatting tags.
# Step 1: Encode ALL HTML entities first to neutralize any malicious content.
my $escaped = encode_entities($comment_raw);

# Step 2: Selectively re-enable only safe, basic formatting tags.
# We whitelist a small set of simple tags with no attributes allowed.
# Allowed tags: <b>, <i>, <u>, <em>, <strong>, <br>, <p>
my @allowed_tags = qw(b i u em strong br p);

for my $tag (@allowed_tags) {
    # Re-enable opening tags (no attributes allowed — the entity-encoded version
    # of <b> is &lt;b&gt;, so we match that pattern).
    # Opening tag without attributes: &lt;tag&gt;
    $escaped =~ s/&lt;($tag)&gt;/<$1>/gi;
    # Closing tag: &lt;/tag&gt;
    $escaped =~ s/&lt;\/($tag)&gt;/<\/$1>/gi;
}

# Step 3: For <br>, also allow <br /> and <br/> forms
$escaped =~ s/&lt;br\s*\/&gt;/<br \/>/gi;

# Step 4: Verify no attribute injection snuck through — strip any tag that
# contains attributes (anything beyond the simple tag name).
# Since we only restored tags from entity-encoded forms with exact matches
# (no attributes), this is already safe, but as defense-in-depth:
# Remove any actual HTML tags that are NOT in our whitelist or that contain attributes.
$escaped =~ s/<(?!\/?(?:b|i|u|em|strong|br|p)\s*\/?>)[^>]*>//gi;

# Also strip any tags from the whitelist that somehow have attributes injected
$escaped =~ s/<(\/?)(?:b|i|u|em|strong|br|p)\s+[^>]*>/&lt;$1tag&gt;/gi;

print $cgi->header(-type => 'text/html', -charset => 'UTF-8');
print <<HTML;
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><title>Discussion Board</title></head>
<body>
<h2>User Comment</h2>
<div class="comment">$escaped</div>
</body>
</html>
